import numpy as np
def logic(x, y):
    m = int(y.get('m', 3)) if isinstance(y, dict) else 3 # 嵌入維度
    delay = int(y.get('d', 1)) if isinstance(y, dict) else 1
    n = len(x)
    if n < m: return np.array([0]), np.array([0.0])
    # 生成排列模式
    def get_pattern(v):
        return tuple(np.argsort(v))
    patterns = [get_pattern(x[i:i+m*delay:delay]) for i in range(n - (m-1)*delay)]
    _, counts = np.unique(patterns, axis=0, return_counts=True)
    probs = counts / len(patterns)
    pe = -np.sum(probs * np.log2(probs)) / np.log2(np.math.factorial(m))
    return np.array([0]), np.array([pe])

